// import { ModalExcelAuthSecondComponent } from '../modals/modal-excel-auth-second/modal-excel-auth-second.component';
import { HttpErrorResponse } from '@angular/common/http';
import { User } from 'src/app/shared/models/users';
import { FirstAndSecondAuthAuditLogRespDTO } from 'src/app/shared/models/audit-logs-dto-first-second';
import { UsersService } from 'src/app/views/users/users.service';
import { ExcelService } from 'src/app/shared/services/excel.service';
